mapper.select:
SELECT COUNT(1)
  FROM ARTAPPM B
  INNER JOIN ARTPROM A ON B.PRO_ID = A.PRO_ID
 WHERE A.STTUS_CODE = 'A'
   /* REQ_ESNTL_ID = 신청자ID(로그인 사용자 uniqId) */
   AND B.REQ_ESNTL_ID = #{reqEsntlId}
   AND B.STTUS_CODE = #{sttusCode}

SELECT COUNT(1)
  FROM ARTAPMM B
  INNER JOIN ARTPROM A ON B.PRO_ID = A.PRO_ID
 WHERE A.STTUS_CODE = 'A'
   AND B.STTUS_CODE = 'A'
   /* REQ_ESNTL_ID = 신청자ID(로그인 사용자 uniqId) */
   AND B.REQ_ESNTL_ID = #{reqEsntlId}
   AND B.STTUS_CODE = #{sttusCode}

